### **Phase 1: 静的レイアウト移行 (1週間)**

#### **1.1 Go側データ出力拡張**
```go
// cmd/beaver/astro.go - 新規作成
package main

import (
    "encoding/json"
    "os"
    "path/filepath"
)

type AstroDataExport struct {
    Issues      []Issue           `json:"issues"`
    Statistics  Statistics        `json:"statistics"`
    Navigation  Navigation        `json:"navigation"`
    Metadata    SiteMetadata      `json:"metadata"`
}

func ExportAstroData(config *Config) error {
    // 既存のデータ処理ロジック活用
    issues, err := ProcessIssues(config)
    if err \!= nil {
        return err
    }

    statistics := CalculateStatistics(issues)
    navigation := BuildNavigation(issues)

    data := AstroDataExport{
        Issues:     issues,
        Statistics: statistics,
        Navigation: navigation,
        Metadata: SiteMetadata{
            GeneratedAt: time.Now(),
            Repository:  config.Repository,
            Version:     version,
        },
    }

    // Astro用JSON出力
    jsonData, err := json.MarshalIndent(data, "", "  ")
    if err \!= nil {
        return err
    }

    outputPath := filepath.Join("beaver-astro", "src", "data", "beaver.json")
    return os.WriteFile(outputPath, jsonData, 0644)
}

// 既存ビルドコマンドに統合
func runBuildCommand(cmd *cobra.Command, args []string) error {
    // 既存HTML生成
    err := runOriginalBuild(cmd, args)
    if err \!= nil {
        return err
    }

    // Astro用データ出力追加
    config, err := loadConfig()
    if err \!= nil {
        return err
    }

    return ExportAstroData(config)
}
```

