### **Phase 2: インタラクティブ機能移行 (2週間)**

#### **2.1 検索機能のReact Island化**
```tsx
// src/components/SearchInterface.tsx
import { useState, useMemo } from 'react';
import type { Issue } from '../types/beaver';

interface Props {
  issues: Issue[];
}

export default function SearchInterface({ issues }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedLabels, setSelectedLabels] = useState<string[]>([]);

  const filteredIssues = useMemo(() => {
    return issues.filter(issue => {
      const matchesSearch = issue.title.toLowerCase()
        .includes(searchQuery.toLowerCase()) ||
        issue.body.toLowerCase().includes(searchQuery.toLowerCase());

      const matchesLabels = selectedLabels.length === 0 ||
        selectedLabels.some(label => issue.labels.includes(label));

      return matchesSearch && matchesLabels;
    });
  }, [issues, searchQuery, selectedLabels]);

  const allLabels = useMemo(() => {
    const labels = new Set<string>();
    issues.forEach(issue => issue.labels.forEach(label => labels.add(label)));
    return Array.from(labels).sort();
  }, [issues]);

  return (
    <div className="search-interface">
      {/* 検索バー */}
      <div className="mb-6">
        <input
          type="text"
          placeholder="Search issues..."
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
        />
      </div>

      {/* ラベルフィルタ */}
      <div className="mb-6">
        <h4 className="font-semibold mb-2">Labels:</h4>
        <div className="flex flex-wrap gap-2">
          {allLabels.map(label => (
            <button
              key={label}
              onClick={() => {
                setSelectedLabels(prev => 
                  prev.includes(label) 
                    ? prev.filter(l => l \!== label)
                    : [...prev, label]
                );
              }}
              className={`px-3 py-1 rounded-full text-sm transition-colors ${
                selectedLabels.includes(label)
                  ? 'bg-blue-500 text-white'
                  : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
              }`}
            >
              {label}
            </button>
          ))}
        </div>
      </div>

      {/* 結果表示 */}
      <div className="results">
        <p className="text-sm text-gray-600 mb-4">
          {filteredIssues.length} issues found
        </p>

        <div className="grid gap-4">
          {filteredIssues.map(issue => (
            <IssueCard key={issue.id} issue={issue} />
          ))}
        </div>
      </div>
    </div>
  );
}

function IssueCard({ issue }: { issue: Issue }) {
  return (
    <div className="border border-gray-200 rounded-lg p-4 hover:shadow-md transition-shadow">
      <h3 className="font-semibold text-lg mb-2">
        <a href={issue.html_url} target="_blank" rel="noopener" 
           className="text-blue-600 hover:text-blue-800">
          #{issue.number} {issue.title}
        </a>
      </h3>

      <div className="flex flex-wrap gap-1 mb-3">
        {issue.labels.map(label => (
          <span key={label} className="px-2 py-1 bg-gray-100 text-xs rounded">
            {label}
          </span>
        ))}
      </div>

      <p className="text-gray-600 text-sm line-clamp-3">
        {issue.body.substring(0, 200)}...
      </p>

      <div className="mt-3 text-xs text-gray-500">
        Created: {new Date(issue.created_at).toLocaleDateString()} by {issue.user.login}
      </div>
    </div>
  );
}
```

