### **Phase 3: 高度機能実装 (2週間)**

#### **3.1 統計ダッシュボード（Chart.js統合）**
```tsx
// src/components/StatisticsChart.tsx
import { Chart as ChartJS, CategoryScale, LinearScale, PointElement, LineElement, Title, Tooltip, Legend } from 'chart.js';
import { Line } from 'react-chartjs-2';
import type { Statistics } from '../types/beaver';

ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, Title, Tooltip, Legend);

interface Props {
  statistics: Statistics;
}

export default function StatisticsChart({ statistics }: Props) {
  const chartData = {
    labels: statistics.timeline?.map(point => point.date) || [],
    datasets: [
      {
        label: 'Open Issues',
        data: statistics.timeline?.map(point => point.open_issues) || [],
        borderColor: 'rgb(75, 192, 192)',
        backgroundColor: 'rgba(75, 192, 192, 0.2)',
      },
      {
        label: 'Closed Issues',
        data: statistics.timeline?.map(point => point.closed_issues) || [],
        borderColor: 'rgb(255, 99, 132)',
        backgroundColor: 'rgba(255, 99, 132, 0.2)',
      }
    ],
  };

  const options = {
    responsive: true,
    plugins: {
      legend: {
        position: 'top' as const,
      },
      title: {
        display: true,
        text: 'Issues Timeline',
      },
    },
  };

  return (
    <div className="bg-white rounded-lg p-6 shadow-sm">
      <Line data={chartData} options={options} />
    </div>
  );
}
```

#### **3.2 ナビゲーション強化**
```tsx
// src/components/InteractiveNavigation.tsx
import { useState, useEffect } from 'react';
import type { NavigationItem } from '../types/beaver';

interface Props {
  navigation: NavigationItem[];
}

export default function InteractiveNavigation({ navigation }: Props) {
  const [activeSection, setActiveSection] = useState<string>('');
  const [expandedSections, setExpandedSections] = useState<Set<string>>(new Set());

  useEffect(() => {
    // Intersection Observer for active section tracking
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            setActiveSection(entry.target.id);
          }
        });
      },
      { threshold: 0.5 }
    );

    navigation.forEach(item => {
      const element = document.getElementById(item.anchor);
      if (element) observer.observe(element);
    });

    return () => observer.disconnect();
  }, [navigation]);

  const toggleSection = (anchor: string) => {
    setExpandedSections(prev => {
      const newSet = new Set(prev);
      if (newSet.has(anchor)) {
        newSet.delete(anchor);
      } else {
        newSet.add(anchor);
      }
      return newSet;
    });
  };

  return (
    <nav className="bg-white rounded-lg p-6 shadow-sm sticky top-6">
      <h3 className="text-lg font-semibold mb-4">📖 目次</h3>
      <ul className="space-y-1">
        {navigation.map(item => (
          <NavigationItem
            key={item.anchor}
            item={item}
            isActive={activeSection === item.anchor}
            isExpanded={expandedSections.has(item.anchor)}
            onToggle={() => toggleSection(item.anchor)}
          />
        ))}
      </ul>
    </nav>
  );
}

function NavigationItem({ item, isActive, isExpanded, onToggle }: {
  item: NavigationItem;
  isActive: boolean;
  isExpanded: boolean;
  onToggle: () => void;
}) {
  return (
    <li>
      <div className="flex items-center">
        <a
          href={`#${item.anchor}`}
          className={`flex-1 px-3 py-2 rounded-md text-sm transition-colors ${
            isActive
              ? 'bg-blue-100 text-blue-800 font-medium'
              : 'text-gray-600 hover:text-blue-600 hover:bg-gray-50'
          }`}
        >
          {item.title}
        </a>
        {item.children && (
          <button
            onClick={onToggle}
            className="p-1 hover:bg-gray-100 rounded"
          >
            <svg
              className={`w-4 h-4 transition-transform ${
                isExpanded ? 'rotate-90' : ''
              }`}
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
            </svg>
          </button>
        )}
      </div>

      {item.children && isExpanded && (
        <ul className="ml-4 mt-1 space-y-1">
          {item.children.map(child => (
            <NavigationItem
              key={child.anchor}
              item={child}
              isActive={isActive}
              isExpanded={false}
              onToggle={() => {}}
            />
          ))}
        </ul>
      )}
    </li>
  );
}
```

