```typescript
// src/components/IssuesDashboard.tsx
import { useState, useMemo } from 'react';
import type { Issue } from '@/types/beaver';

interface Props {
  data: Issue[];
}

export default function IssuesDashboard({ data }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedLabels, setSelectedLabels] = useState<string[]>([]);

  const filteredIssues = useMemo(() => {
    return data.filter(issue => {
      const matchesSearch = issue.title.toLowerCase()
        .includes(searchQuery.toLowerCase());
      const matchesLabels = selectedLabels.length === 0 || 
        selectedLabels.some(label => issue.labels.includes(label));
      return matchesSearch && matchesLabels;
    });
  }, [data, searchQuery, selectedLabels]);

  return (
    <div className="issues-dashboard">
      <div className="search-controls">
        <input
          type="text"
          placeholder="Search issues..."
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          className="search-input"
        />
        <LabelFilter 
          allLabels={getAllLabels(data)}
          selected={selectedLabels}
          onChange={setSelectedLabels}
        />
      </div>

      <div className="issues-grid">
        {filteredIssues.map(issue => (
          <IssueCard key={issue.id} issue={issue} />
        ))}
      </div>
    </div>
  );
}
```

