```typescript
// src/alpine-beaver.ts
import Alpine from 'alpinejs';
import type { BeaverData, Issue } from './types/beaver';

interface BeaverAppData {
  data: BeaverData | null;
  searchQuery: string;
  selectedLabels: string[];
  currentView: string;
}

declare global {
  interface Window {
    beaverApp(): BeaverAppData;
  }
}

window.beaverApp = function(): BeaverAppData {
  return {
    data: null,
    searchQuery: '',
    selectedLabels: [],
    currentView: 'dashboard',

    get filteredIssues(): Issue[] {
      if (\!this.data?.issues) return [];

      return this.data.issues.filter(issue => {
        const matchesSearch = issue.title.toLowerCase()
          .includes(this.searchQuery.toLowerCase());
        const matchesLabels = this.selectedLabels.length === 0 ||
          this.selectedLabels.some(label => issue.labels.includes(label));
        return matchesSearch && matchesLabels;
      });
    },

    loadData(): void {
      const script = document.getElementById('beaver-data');
      if (script?.textContent) {
        this.data = JSON.parse(script.textContent);
      }
    }
  };
};

Alpine.start();
```

